"""DeepLake Managed Service Client.

Agent-friendly SDK for ingesting data into DeepLake managed tables.

Usage:
    from deeplake.managed import Client

    client = Client(token="dl_xxx", workspace_id="my-workspace")

    # Ingest files (FILE schema)
    client.ingest("videos", {"path": ["video1.mp4"]}, schema={"path": "FILE"})

    # Ingest data directly (dict)
    client.ingest("embeddings", {"text": [...], "embedding": [...]})

    # Ingest from HuggingFace
    client.ingest("cifar", {"_huggingface": "cifar10"})

    # Fluent query
    results = client.table("videos").select("id", "text").limit(10)()

    # Raw SQL
    results = client.query("SELECT * FROM videos LIMIT 10")

Async variant (requires aiohttp):
    from deeplake.managed import AsyncClient

    client = AsyncClient(token="dl_xxx")
    await client.ingest("videos", {"path": ["video1.mp4"]}, schema={"path": "FILE"})
    results = await client.table("videos").select("id").limit(10).execute()
"""

from .client import Client, ManagedDataset, ManagedQueryBuilder
from .async_client import AsyncClient, AsyncManagedQueryBuilder
from .errors import (
    ManagedServiceError,
    AuthError,
    CredentialsError,
    IngestError,
    TableError,
    TokenError,
    WorkspaceError,
)

